SELECT u.id, u.name, u.username, u.phone, u.status, GROUP_CONCAT(r.id) AS roleIds, GROUP_CONCAT(r.name SEPARATOR ',') AS roleNames FROM users u LEFT JOIN user_role ur ON u.id = ur.user_id LEFT JOIN roles r ON ur.role_id = r.id
AND (u.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%') OR u.phone LIKE CONCAT('%',#{keyword},'%'))
AND ur.role_id = #{roleId}
AND u.status = #{status}
GROUP BY u.id ORDER BY u.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(DISTINCT u.id)
FROM users u
LEFT JOIN user_role ur ON u.id = ur.user_id


        AND (u.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%') OR u.phone LIKE CONCAT('%',#{keyword},'%'))


